use std::path::Path;
use std::process::ExitCode;

use clap::{CommandFactory, FromArgMatches, Parser, Subcommand};
use clap_complete::CompleteEnv;
use log::error;

use crate::subcommand::SubcommandRunner;

/// Banner string emitted as the first line of normal command runs
/// and shown at the top of subcommand `--help` output. Built from
/// `Cargo.toml`'s name + version at compile time so it stays in
/// sync with the bumped version.
const BANNER: &str = concat!(env!("CARGO_PKG_NAME"), " ", env!("CARGO_PKG_VERSION"));

/// Top-level about line — name, version, and the project tagline
/// on a single line. Used as the top-level `about` so `vc-x1 -h`
/// reads as one banner-plus-tagline header instead of two stacked
/// lines.
const TOP_ABOUT: &str = concat!(
    env!("CARGO_PKG_NAME"),
    " ",
    env!("CARGO_PKG_VERSION"),
    " - jj workspace tooling"
);

/// Build the clap command tree with `BANNER` set as `before_help`
/// on every subcommand (transitively). Top-level skips `before_help`
/// because its own `about` already carries the name+version+tagline.
/// Walks via `mut_subcommand` so individual subcommand
/// `#[command(long_about = ...)]` blocks don't have to repeat the
/// banner text.
fn cli_with_banner() -> clap::Command {
    fn add_to_subs(mut cmd: clap::Command) -> clap::Command {
        let names: Vec<String> = cmd
            .get_subcommands()
            .map(|c| c.get_name().to_string())
            .collect();
        for name in names {
            cmd = cmd.mut_subcommand(name, add_with_banner);
        }
        cmd
    }
    fn add_with_banner(mut cmd: clap::Command) -> clap::Command {
        cmd = cmd.before_help(BANNER);
        let names: Vec<String> = cmd
            .get_subcommands()
            .map(|c| c.get_name().to_string())
            .collect();
        for name in names {
            cmd = cmd.mut_subcommand(name, add_with_banner);
        }
        cmd
    }
    add_to_subs(Cli::command())
}

#[derive(Parser, Debug)]
#[command(about = TOP_ABOUT, max_term_width = 80)]
pub struct Cli {
    /// Print the `vc-x1 X.Y.Z` banner as the first line, then
    /// continue. With no subcommand, prints the banner and exits.
    ///
    /// Replaces clap's auto-version (which would exit after
    /// printing): the banner now rides along with normal
    /// subcommand execution rather than gating it, so scripts
    /// can capture the version *and* the command's output in
    /// one invocation.
    #[arg(short = 'V', long = "version", global = true, action = clap::ArgAction::SetTrue)]
    pub version: bool,

    /// Verbose output: -v debug, -vv trace
    #[arg(short, long, global = true, action = clap::ArgAction::Count)]
    pub verbose: u8,

    /// Log file path (captures all levels)
    #[arg(long, global = true)]
    pub log: Option<std::path::PathBuf>,

    #[command(subcommand)]
    pub(crate) command: Option<Commands>,
}

#[derive(Subcommand, Debug)]
pub(crate) enum Commands {
    /// Print the changeID for a revision
    Chid(chid::ChidArgs),

    /// Show full description of a commit
    Desc(desc::DescArgs),

    /// List commits in a jj repo
    List(list::ListArgs),

    /// Show commit details and diff summary
    Show(show::ShowArgs),

    /// Check the bot repo is published (main matches main@origin)
    #[command(
        long_about = "Check the bot repo is published (main matches main@origin).\n\n\
        At rest the bot repo's `main` always matches `main@origin` — the\n\
        bookmark only moves inside a push / squash-push run, which\n\
        publishes it in the same invocation. A mismatch means an earlier\n\
        publish was lost. Read-only and cheap (two jj lookups; no cargo\n\
        steps); also verifies main's remote refs are tracked. Exits\n\
        non-zero on any finding and fixes nothing — resolve with\n\
        `vc-x1 squash-push -R <bot-repo>`."
    )]
=== subcommand.rs ===
//! `SubcommandRunner` trait
//!
//! The purpose is to simplify invoking a subcommand so `main`
//! can invoke any subcommand with one line:
//!
//! `Commands::Chid(args) => args.dispatch(&ctx),`
//!
//! Instead of the ~11 lines that the default `dispatch` below
//! now encapsulates.
//!
//! Implementors provide:
//!
//! - [`SubcommandRunner::to_params`] — build the clap-free
//!   `Params` from the clap `Args` (covers both `From` /
//!   `TryFrom` shapes uniformly via `Result<_, String>`).
//! - [`SubcommandRunner::run`] — the subcommand body.
//!
//! The default [`SubcommandRunner::dispatch`] builds `Params`
//! via `to_params`, runs via `run`, and maps the result to
//! `ExitCode`. Errors at any stage log via `error!` and return
//! `ExitCode::FAILURE`. `Context` is loaded once in `main` and
//! passed in by reference so a single `Context` is shared across
//! the (one) match arm that actually runs.
//!
//! ## See also
//!
//! - The wider CLI-args / subcommand-layer split this trait
//!   formalizes: [`ARCHITECTURE.md > args → Context + Params`][arch].
//! - Cycle design, ladder, evaluation gate:
//!   [`chores-10.md > 0.50.0-0`][open].
//! - Worked example, trait-shape decisions, naming:
//!   [`chores-10.md > 0.50.0-1`][port].
//! - First implementor: [`crate::chid`].
//!
//! [arch]: https://github.com/winksaville/vc-x1/blob/main/ARCHITECTURE.md#args--context--params
//! [open]: https://github.com/winksaville/vc-x1/blob/main/notes/chores/chores-10.md#chore-open-subcommand-trait-sweep-0500-0
//! [port]: https://github.com/winksaville/vc-x1/blob/main/notes/chores/chores-10.md#refactor-subcommandrunner-trait--chid-0500-1

use std::process::ExitCode;

use log::error;

use crate::context::Context;

/// Trait implemented by every subcommand's clap `Args` type so
/// `main.rs` can dispatch via a single `args.dispatch(&ctx)`
/// call.
pub trait SubcommandRunner {
    /// The clap-free `Params` struct the subcommand body
    /// consumes.
    type Params;

    /// Build `Params` from `Args`. `Result<_, String>` absorbs
    /// both `From` (return `Ok(...)`) and `TryFrom` (forward
    /// the error) shapes uniformly.
    fn to_params(&self) -> Result<Self::Params, String>;

    /// Run the subcommand body.
    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>>;

    /// Default dispatch: build `Params` via `to_params`, bracket
    /// the run with `crate::bm_track` enter/exit, execute via
    /// `run`, and map the result to `ExitCode`. Errors at any
    /// stage log via `error!` and return `ExitCode::FAILURE`.
    /// `bm_track` itself emits at `debug!`, so default runs stay
    /// quiet — no per-call gate is needed here.
    fn dispatch(&self, ctx: &Context) -> ExitCode {
        let params = match self.to_params() {
            Ok(p) => p,
            Err(e) => {
                error!("{e}");
                return ExitCode::FAILURE;
            }
        };

        // Command name is the first positional after the binary;
        // clap has already validated it by the time we reach
        // dispatch (top-level parse errors exit earlier).
        let command_name = std::env::args().nth(1).unwrap_or_else(|| "?".to_string()); // OK: default when somehow invoked without a subcommand

        crate::bm_track("enter", &command_name);
        let exit_code = match Self::run(ctx, &params) {
            Ok(()) => ExitCode::SUCCESS,
            Err(e) => {
                error!("{e}");
                ExitCode::FAILURE
            }
        };
        crate::bm_track("exit ", &command_name);
        exit_code
    }
}

