/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FileLimit {
    /// Don't show changed files section at all.
    None,
    /// Show up to N files (with first/last split if truncated).
    Cap(usize),
    /// Show all files.
    All,
}

impl FileLimit {
