    /// None, `"all"` → All, otherwise a positive integer → Cap(n).
    /// Called at the boundary by `ShowParams::try_from`.
    pub fn parse(s: &str) -> Result<Self, String> {
        match s {
            "0" => Ok(FileLimit::None),
            "all" => Ok(FileLimit::All),
